def assess(record: dict) -> str:
    required = {'baseline_frozen', 'case_id', 'jobs', 'metrics', 'stakeholders'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get("jobs", 0) > 0 and record.get("baseline_frozen") is True:
        return 'PASS'
    return 'REOPEN_CF1'

